/// Custom exception for HTTP service errors
class HttpServiceException implements Exception {
  final String message;
  final int? statusCode;
  final String? url;
  final dynamic originalError;

  HttpServiceException({
    required this.message,
    this.statusCode,
    this.url,
    this.originalError,
  });

  @override
  String toString() {
    final buffer = StringBuffer('HttpServiceException: $message');
    if (statusCode != null) buffer.write(' (Status: $statusCode)');
    if (url != null) buffer.write(' [URL: $url]');
    return buffer.toString();
  }
}

/// Enum to distinguish between cloud API and local IoT device targets
enum EndpointType {
  cloudApi,
  iotDevice,
}

/// Configuration for an IoT device
class IoTDeviceConfig {
  final String ipAddress;
  final int port;
  final bool useHttps;

  const IoTDeviceConfig({
    required this.ipAddress,
    this.port = 80,
    this.useHttps = false,
  });

  String get baseUrl {
    final scheme = useHttps ? 'https' : 'http';
    return '$scheme://$ipAddress:$port';
  }
}

/// Response wrapper for unified response handling
class ApiResponse<T> {
  final T? data;
  final int statusCode;
  final Map<String, String> headers;
  final bool isSuccess;

  ApiResponse({
    this.data,
    required this.statusCode,
    required this.headers,
    required this.isSuccess,
  });
}

