  /// Execute an HTTP request with retry logic
  Future<ApiResponse<Map<String, dynamic>>> _executeWithRetry(
    Future<http.Response> Function() requestFn,
    String url,
    EndpointType endpointType, {
    int? maxRetries,
  }) async {
    final retries = maxRetries ?? _maxRetries;
    final timeout = endpointType == EndpointType.cloudApi ? _cloudTimeout : _iotTimeout;

    Exception? lastException;

    for (int attempt = 0; attempt < retries; attempt++) {
      try {
        final response = await requestFn().timeout(timeout);
        return _processResponse(response, url);
      } on TimeoutException catch (e) {
        lastException = HttpServiceException(
          message: 'Request timed out after ${timeout.inSeconds}s',
          url: url,
          originalError: e,
        );
        // For IoT devices, don't retry on timeout (device likely offline)
        if (endpointType == EndpointType.iotDevice) break;
      } on SocketException catch (e) {
        lastException = HttpServiceException(
          message: 'Network error: Unable to connect to $url',
          url: url,
          originalError: e,
        );
        // For IoT devices, don't retry on socket errors
        if (endpointType == EndpointType.iotDevice) break;
      } on HttpServiceException {
        rethrow;
      } on http.ClientException catch (e) {
        lastException = HttpServiceException(
          message: 'Client error: ${e.message}',
          url: url,
          originalError: e,
        );
      } catch (e) {
        lastException = HttpServiceException(
          message: 'Unexpected error: $e',
          url: url,
          originalError: e,
        );
      }

      // Wait before retrying (exponential backoff)
      if (attempt < retries - 1) {
        await Future.delayed(Duration(milliseconds: 500 * (attempt + 1)));
      }
    }

    throw lastException ??
        HttpServiceException(
          message: 'Request failed after $retries attempts',
          url: url,
        );
  }

  /// Process the HTTP response into a unified ApiResponse
  ApiResponse<Map<String, dynamic>> _processResponse(
    http.Response response,
    String url,
  ) {
    final isSuccess = response.statusCode >= 200 && response.statusCode < 300;

    Map<String, dynamic>? data;
    if (response.body.isNotEmpty) {
      try {
        final decoded = jsonDecode(response.body);
        if (decoded is Map<String, dynamic>) {
          data = decoded;
        } else {
          data = {'data': decoded};
        }
      } catch (_) {
        data = {'raw': response.body};
      }
    }

    if (!isSuccess) {
      throw HttpServiceException(
        message: _getErrorMessage(response.statusCode, data),
        statusCode: response.statusCode,
        url: url,
      );
    }

    return ApiResponse<Map<String, dynamic>>(
      data: data,
      statusCode: response.statusCode,
      headers: response.headers,
      isSuccess: isSuccess,
    );
  }

  String _getErrorMessage(int statusCode, Map<String, dynamic>? data) {
    // Try to extract error message from response body
    if (data != null) {
      if (data.containsKey('message')) return data['message'].toString();
      if (data.containsKey('error')) return data['error'].toString();
      if (data.containsKey('detail')) return data['detail'].toString();
    }

    switch (statusCode) {
      case 400:
        return 'Bad request';
      case 401:
        return 'Unauthorized - Please check your authentication';
      case 403:
        return 'Forbidden - You do not have access to this resource';
      case 404:
        return 'Resource not found';
      case 408:
        return 'Request timeout';
      case 429:
        return 'Too many requests - Rate limit exceeded';
      case 500:
        return 'Internal server error';
      case 502:
        return 'Bad gateway';
      case 503:
        return 'Service unavailable';
      default:
        return 'HTTP error $statusCode';
    }
