// ==================== Example Usage ====================

Future<void> main() async {
  final httpService = HttpService();

  // Set auth token for cloud API
  httpService.setAuthToken('your-jwt-token-here');

  // Register IoT devices
  httpService.registerDevice(
    'thermostat-living-room',
    const IoTDeviceConfig(
      ipAddress: '192.168.1.100',
      port: 80,
      useHttps: false,
    ),
  );

  httpService.registerDevice(
    'smart-lock-front',
    const IoTDeviceConfig(
      ipAddress: '192.168.1.101',
      port: 443,
      useHttps: true,
    ),
  );

  httpService.registerDevice(
    'camera-garage',
    const IoTDeviceConfig(
      ipAddress: '192.168.1.102',
      port: 8080,
      useHttps: false,
    ),
  );

  try {
    // === Cloud API Examples ===

    // GET user profile from cloud
    print('--- Cloud API: Get User Profile ---');
    final profileResponse = await httpService.cloudGet('/api/v1/user/profile');
    print('Profile: ${profileResponse.data}');

    // POST new device registration to cloud
    print('\n--- Cloud API: Register Device ---');
    final registerResponse = await httpService.cloudPost(
      '/api/v1/devices',
      body: {
        'name': 'Living Room Thermostat',
        'type': 'thermostat',
        'ip': '192.168.1.100',
      },
    );
    print('Registered: ${registerResponse.data}');

    // GET devices list with query params
    print('\n--- Cloud API: List Devices ---');
    final devicesResponse = await httpService.cloudGet(
      '/api/v1/devices',
      queryParams: {'type': 'thermostat', 'status': 'online'},
    );
    print('Devices: ${devicesResponse.data}');

    // === IoT Device Examples ===

    // GET temperature from thermostat (HTTP)
    print('\n--- IoT: Get Temperature ---');
    final tempResponse = await httpService.deviceGet(
      'thermostat-living-room',
      '/api/temperature',
    );
    print('Temperature: ${tempResponse.data}');

    // POST set temperature on thermostat
    print('\n--- IoT: Set Temperature ---');
    final setTempResponse = await httpService.devicePost(
      'thermostat-living-room',
      '/api/temperature',
      body: {'target': 72, 'mode': 'heat'},
    );
    print('Set temp result: ${setTempResponse.data}');

    // GET lock status (HTTPS device)
    print('\n--- IoT: Get Lock Status ---');
    final lockResponse = await httpService.deviceGet(
      'smart-lock-front',
      '/api/status',
    );
    print('Lock status: ${lockResponse.data}');

    // POST unlock command
    print('\n--- IoT: Unlock Door ---');
    final unlockResponse = await httpService.devicePost(
      'smart-lock-front',
      '/api/unlock',
      body: {'pin': '1234', 'duration': 30},
    );
    print('Unlock result: ${unlockResponse.data}');

    // Direct device request (device not registered)
    print('\n--- IoT: Direct Request ---');
    final directResponse = await httpService.directDeviceRequest(
      '192.168.1.200',
      '/api/status',
      method: 'GET',
      port: 80,
      useHttps: false,
    );
    print('Direct response: ${directResponse.data}');

    // === Health Checks ===

    print('\n--- Health Checks ---');
    final cloudHealthy = await httpService.isCloudApiHealthy();
    print('Cloud API healthy: $cloudHealthy');

    final thermostatOnline = await httpService.isDeviceOnline(
      'thermostat-living-room',
    );
    print('Thermostat online: $thermostatOnline');

    // === Device Discovery ===

    print('\n--- Device Discovery ---');
    final discoveredDevices = await httpService.discoverDevices(
      subnet: '192.168.1',
      port: 80,
      startRange: 100,
      endRange: 110,
      timeout: const Duration(seconds: 1),
    );
    print('Discovered ${discoveredDevices.length} devices:');
    for (final device in discoveredDevices) {
      print('  - ${device.ipAddress}:${device.port}');
    }

    // === Cloud API Update & Delete ===

    print('\n--- Cloud API: Update Device ---');
    final updateResponse = await httpService.cloudPut(
      '/api/v1/devices/thermostat-living-room',
      body: {
        'name': 'Living Room Smart Thermostat',
        'firmware': '2.1.0',
      },
    );
    print('Updated: ${updateResponse.data}');

    print('\n--- Cloud API: Patch Settings ---');
    final patchResponse = await httpService.cloudPatch(
      '/api/v1/user/settings',
      body: {'notifications': true},
    );
    print('Patched: ${patchResponse.data}');
  } on HttpServiceException catch (e) {
    print('HTTP Service Error: $e');
    if (e.statusCode == 401) {
      print('Need to refresh authentication token');
    }
  } catch (e) {
    print('Unexpected error: $e');
  } finally {
    httpService.dispose();
  }
}